import torch
from transformers import AutoTokenizer

# load the tokenizer
tokenizer = AutoTokenizer.from_pretrained('CohereLabs/North-Mini-Code-1.0')

# raw text
text = "This raw text will be tokenized"

# create tokenize using tokenizer
tokens = tokenizer.tokenize(text)
token_id = tokenizer.encode(text) # directly create token ids

print(f"Tokens: {tokens}")
print(f"Token IDs: {token_id}")

# create token embedding layer
VOCABULARY_SIZE: int = tokenizer.vocab_size
EMBEDDING_DIM: int = 768
token_embedding_layer = torch.nn.Embedding(
    num_embeddings=VOCABULARY_SIZE,
    embedding_dim=EMBEDDING_DIM
)

# get token embeddings (IDs must be passed as a tensor, not a list)
print(f"Max token ID: {max(token_id)}")
print(f"Vocab size for embedding layer: {VOCABULARY_SIZE}")
token_emb = token_embedding_layer(torch.tensor(token_id, dtype=torch.long))
print(f'Token Embeddings shape: {token_emb.shape}')
print(f'Token Embeddings: {token_emb}')

"""# Attention Machanism

![image.png](data:image/png;base64,)

![image.png](data:image/png;base64,)

![image.png](data:image/png;base64,)

![image.png](data:image/png;base64,)
"""

import math
import torch
from torch import nn
import torch.nn.functional as F

class CasualSelfAttention(nn.Module):

  def __init__(self, embedding_dim: int, num_heads: int, max_token_length: int, bias: bool=False, dropout: float=0.0):
    super().__init__()

    assert embedding_dim % num_heads == 0
    #"Embedding dimension must be divisible by the number of heads"

    # key, query, value projections for all heads, but in a batch
    # Output is 3X the dimension because it includes key, query and value
    self.c_attn = nn.Linear(embedding_dim, 3*embedding_dim, bias=bias)

    #projection of concatenated attention head outputs
    self.c_proj = nn.Linear(embedding_dim, embedding_dim, bias=bias)

    # regularization
    self.attn_dropout = nn.Dropout(dropout)
    self.resid_dropout = nn.Dropout(dropout)
    self.num_heads = num_heads
    self.embedding_dim = embedding_dim

    # causal mask to ensure that attention is only applied to
    # the left in the input sequence
    self.register_buffer("mask", torch.tril(torch.ones(max_token_length, max_token_length)))

  def forward(self, x):
    B, T, C = x.size()
    # batch size, sequence length, embedding dimensionality

    # Compute query, key, and value vectors for all heads in batch
    # split the output into separate query, key, and value tensorsd
    # [B, T, embedding_dim]
    q, k, v = self.c_attn(x).split(self.embedding_dim, dim=2)

    # reshape tensor into sequence of smaller token vectors for each head
    k = k.view(B, T, self.num_heads, self.embedding_dim // self.num_heads).transpose(1,2) # [B, T, num_head, emnedding_dim//num_head]
    q = q.view(B, T, self.num_heads, self.embedding_dim//self.num_heads).transpose(1,2) # [B, T, num_head, emnedding_dim//num_head]
    v = v.view(B, T, self.num_heads, self.embedding_dim//self.num_heads).transpose(1,2) # [B, T, num_head, emnedding_dim//num_head]

    # Compute the attention matrix, perform maskeing, and apply dropout
    att = (q @ k.transpose(-2, -1)) * (1.0 / math.sqrt(k.size(-1)))
    att = att.masked_fill(self.mask[:,:,:T,:T] == 0, float("-inf"))
    att = F.softmax(att, dim=-1)
    att = self.attn_dropout(att)

    # compute output vectors for each token
    y = att @ v # [B, num_head, T, T] x [B, num_head, T, emnedding_dim//num_head] -> [B, num_head, T, emnedding_dim//num_head]

    # Concatenate outputs from each attention head and linearly project
    y = y.transpose(1, 2).contiguous().view(B, T, self.embedding_dim) # [B, num_head, T, emnedding_dim//num_head] -> [B, T, embedding_dim]
    y = self.resid_dropout(self.c_proj(y))
    return y

"""# Feed-Forword Network

![image.png](data:image/png;base64,)
"""

from torch import nn

class MLP(nn.Module):

  def __init__(self, embedding_dim: int, bias: bool=False, droput: float=0.2):
    super().__init__()

    self.c_fc = nn.Linear(embedding_dim, 4*embedding_dim, bias=bias)
    self.gelu = nn.GELU()
    self.c_proj = nn.Linear(4*embedding_dim, embedding_dim, bias=bias)
    self.dropout = nn.Dropout(droput)

  def forword(self, x):
    x = self.c_fc(x)
    x = self.gelu(x)
    x = self.c_proj(x)
    x = self.dropout(x)
    return x

"""# Decoder-Only Transformer Block

![image.png](data:image/png;base64,)

![image.png](data:image/png;base64,)
"""

from torch import nn

class Block(nn.Module):

  def __init__(self, embedding_dim: int, num_head: int, max_seq_length: int, bias: bool=False, dropout: float=0.2):
    super().__init__()

    self.ln_1 = nn.LayerNorm(embedding_dim)
    self.attn = CasualSelfAttention(embedding_dim, num_head, max_token_length=max_seq_length, bias=bias, dropout=dropout)
    self.ln_2 = nn.LayerNorm(embedding_dim)
    self.mlp = MLP(embedding_dim, bias, dropout)

  def forward(self, x):
    x = x + self.attn(self.ln_1(x))
    x = x + self.mlp(self.ln_2(x))

    return x

"""# Decoder-Only Transformer Architecture

![image.png](data:image/png;base64,)
"""

import torch
from torch import nn
import torch.nn.functional as F

class GPT(nn.Module):

  def __init__(self, embedding_dim: int, num_head: int, max_seq_length: int, vocabulary: int, layers: int, bias: bool=False, dropout: float=0.2):
    super().__init__()
    self.max_seq_length = max_seq_length
    self.transformer = nn.ModuleDict(dict(
        wte = nn.Embedding(vocabulary, embedding_dim),
        wpe = nn.Embedding(max_seq_length, embedding_dim),
        drop = nn.Dropout(dropout),
        # Pass max_seq_length and other parameters correctly to Block
        blocks = nn.ModuleList([Block(embedding_dim, num_head, max_seq_length, bias=bias, dropout=dropout) for _ in range(layers)]),
        ln_f = nn.LayerNorm(embedding_dim),
        head = nn.Linear(embedding_dim, vocabulary, bias=False)
    ))

  def forward(self, idx, targets=None):
    device = idx.device
    b, t = idx.size()

    # Crop idx to max_seq_length if it exceeds the model's capacity
    if t > self.max_seq_length:
        idx = idx[:, -self.max_seq_length:]
        t = self.max_seq_length
        if targets is not None:
            targets = targets[:, -self.max_seq_length:]

    pos = torch.arange(0, t, dtype=torch.long, device=device).unsqueeze(0)

    x = self.transformer.wte(idx) + self.transformer.wpe(pos)
    x = self.transformer.drop(x)

    for block in self.transformer.blocks:
      x = block(x)
    x = self.transformer.ln_f(x)

    logits = None
    loss = None

    if targets is not None:
      logits = self.transformer.head(x)
      loss = F.cross_entropy(
          logits.view(-1, logits.size(-1)),
          targets.view(-1),
          ignore_index = -1,
      )
    else:
        logits = self.transformer.head(x[:,[-1],:])
        loss = None

    return logits, loss

import torch.nn.functional as F

def generate_next_token(model, idx, max_new_tokens, max_seq_length, temperature=1.0, top_k=None):
    """
    Generates new tokens using the provided model.

    Args:
        model: The GPT model instance.
        idx: A torch.Tensor of shape (batch_size, current_sequence_length) representing the input token IDs.
        max_new_tokens: The maximum number of new tokens to generate.
        max_seq_length: The maximum sequence length the model can handle.
        temperature: Controls randomness in sampling. Higher values make output more random.
        top_k: If not None, samples from the top K most likely tokens.

    Returns:
        A torch.Tensor containing the original and newly generated token IDs.
    """
    for _ in range(max_new_tokens):
        # Crop idx to the last max_seq_length tokens if it exceeds the model's capacity
        idx_cond = idx if idx.size(1) <= max_seq_length else idx[:, -max_seq_length:]

        # Get predictions (logits) for the next token
        logits, _ = model(idx_cond)

        # Focus on the logits for the last token in the sequence
        logits = logits[:, -1, :]

        # Apply temperature for sampling
        if temperature != 1.0:
            logits = logits / temperature

        # Apply top-k sampling
        if top_k is not None:
            # Get the top k values and their indices
            v, _ = torch.topk(logits, min(top_k, logits.size(-1)))
            # Set logits of tokens outside the top-k to -infinity
            logits[logits < v[:, [-1]]] = -float('Inf')

        # Convert logits to probabilities using softmax
        probs = F.softmax(logits, dim=-1)

        # Sample the next token from the probability distribution
        idx_next = torch.multinomial(probs, num_samples=1)

        # Append the sampled token to the sequence
        idx = torch.cat((idx, idx_next), dim=1)

    return idx

# --- Model and Generation Setup ---

# Explicitly define variables from previous cells
VOCABULARY_SIZE: int = tokenizer.vocab_size
EMBEDDING_DIM: int = 768 # Value from cell QVJ5ymxTJASd

# Define parameters for the GPT model
GPT_EMBEDDING_DIM = EMBEDDING_DIM
GPT_NUM_HEADS = 8
GPT_MAX_SEQ_LENGTH = 256 # A reasonable default
GPT_VOCABULARY_SIZE = VOCABULARY_SIZE
GPT_NUM_LAYERS = 6
GPT_BIAS = False
GPT_DROPOUT = 0.0

# Instantiate the corrected GPT model
model = GPT(
    embedding_dim=GPT_EMBEDDING_DIM,
    num_head=GPT_NUM_HEADS,
    max_seq_length=GPT_MAX_SEQ_LENGTH,
    vocabulary=GPT_VOCABULARY_SIZE,
    layers=GPT_NUM_LAYERS,
    bias=GPT_BIAS,
    dropout=GPT_DROPOUT
)

# Prepare initial input token IDs
input_idx = torch.tensor(token_id, dtype=torch.long).unsqueeze(0) # Add batch dimension

print("--- Initial Model Forward Pass (using the original input sequence) ---")
# Call the model's forward pass directly to get logits and loss for the initial sequence
# Since we are not doing training, targets=None, so loss will be None.
initial_logits, initial_loss = model(input_idx)
print(f"Logits shape: {initial_logits.shape}")
print(f"Logits (first 5 values of the last token's logits): {initial_logits[0, -1, :5]}")
print(f"Loss: {initial_loss}")

print("\n--- Running generate_next_token function ---")
# Call the generate_next_token function
# Let's generate 5 new tokens for demonstration
MAX_NEW_TOKENS = 5
TEMPERATURE = 1.0
TOP_K = 50 # Using top_k for more controlled generation

generated_idx = generate_next_token(
    model,
    input_idx,
    max_new_tokens=MAX_NEW_TOKENS,
    max_seq_length=GPT_MAX_SEQ_LENGTH,
    temperature=TEMPERATURE,
    top_k=TOP_K
)

print(f"\nOriginal Token IDs: {input_idx.squeeze(0).tolist()}")
print(f"Generated Token IDs (including original): {generated_idx.squeeze(0).tolist()}")

# To show the logits and loss that would result from the *entire generated sequence*,
# we can pass the `generated_idx` back through the model once.
# This demonstrates the final prediction layer's output on the full sequence.
print("\n--- Model Forward Pass (using the full generated sequence) ---")
final_generated_logits, final_generated_loss = model(generated_idx)
print(f"Logits shape (for the full generated sequence): {final_generated_logits.shape}")
print(f"Logits (first 5 values of the last token's logits for the full sequence): {final_generated_logits[0, -1, :5]}")
print(f"Loss: {final_generated_loss}")